import{_ as e,c as d,o,a1 as a}from"./chunks/framework.DDNAyvCW.js";const r="/assets/llms.D2PJxED4.png",m=JSON.parse('{"title":"模型列表","description":"","frontmatter":{},"headers":[],"relativePath":"docs/ai/llms/index.md","filePath":"docs/ai/llms/index.md"}'),n={name:"docs/ai/llms/index.md"};function l(s,t,i,h,c,p){return o(),d("div",null,t[0]||(t[0]=[a('<h1 id="模型列表" tabindex="-1">模型列表 <a class="header-anchor" href="#模型列表" aria-label="Permalink to &quot;模型列表&quot;">​</a></h1><p>Chaterm 开箱即支持多种 AI 模型提供商，您还可以添加自定义提供商以获得最大灵活性。</p><p><img src="'+r+'" alt=""></p><h2 id="内置模型" tabindex="-1">内置模型 <a class="header-anchor" href="#内置模型" aria-label="Permalink to &quot;内置模型&quot;">​</a></h2><p>Chaterm 内置了多个高质量的预配置模型，开箱即用，无需额外设置。只需在任何 AI 对话中从模型下拉菜单选择即可。</p><h2 id="快速开始-添加您的第一个自定义模型" tabindex="-1">快速开始：添加您的第一个自定义模型 <a class="header-anchor" href="#快速开始-添加您的第一个自定义模型" aria-label="Permalink to &quot;快速开始：添加您的第一个自定义模型&quot;">​</a></h2><p>按照以下步骤添加自定义模型提供商。下面以 OpenAI 为例，其他提供商的流程类似。</p><ol><li>点击右上角齿轮图标打开<strong>设置</strong>。</li><li>在左侧菜单中导航到**&quot;模型&quot;**选项卡。</li><li>点击**&quot;添加模型&quot;**。</li><li>从提供商列表中选择 <strong>OpenAI</strong>（或您偏好的提供商）。</li><li>输入 <strong>API 端点 URL</strong>（例如 <code>https://api.openai.com/v1</code>）。</li><li>粘贴您的 <strong>API 密钥</strong>。</li><li>输入或选择<strong>模型名称</strong>（例如 <code>gpt-5</code>）。</li><li>点击**&quot;测试连接&quot;** -- 显示成功消息表示一切正常。</li><li>点击**&quot;保存&quot;** -- 该模型现在会出现在所有 AI 对话的模型下拉菜单中。</li></ol><div class="tip custom-block"><p class="custom-block-title">推荐首次设置</p><p>如果您是 Chaterm AI 功能的新用户，建议从 <strong>DeepSeek</strong> 或 <strong>OpenAI</strong> 开始。两者都只需要一个 API 密钥，设置简单直观，并且提供强大的通用模型，适合命令生成和 Agent 任务。</p></div><hr><h2 id="提供商参考" tabindex="-1">提供商参考 <a class="header-anchor" href="#提供商参考" aria-label="Permalink to &quot;提供商参考&quot;">​</a></h2><h3 id="_1-litellm" tabindex="-1">1. LiteLLM <a class="header-anchor" href="#_1-litellm" aria-label="Permalink to &quot;1. LiteLLM&quot;">​</a></h3><p>通过统一的 LiteLLM 网关连接多种模型提供商。</p><table tabindex="0"><thead><tr><th>配置项</th><th>说明</th><th>是否必需</th></tr></thead><tbody><tr><td><strong>URL 地址</strong></td><td>LiteLLM 服务端点</td><td>是</td></tr><tr><td><strong>API Key</strong></td><td>LiteLLM 网关的访问密钥</td><td>是</td></tr><tr><td><strong>模型名称</strong></td><td>模型标识符（例如 <code>gpt-5</code>、<code>claude-sonnet-4-6</code>）</td><td>是</td></tr></tbody></table><p><strong>最适合：</strong> 已经运行 LiteLLM 代理、通过统一端点访问多个提供商的团队。</p><hr><h3 id="_2-openai" tabindex="-1">2. OpenAI <a class="header-anchor" href="#_2-openai" aria-label="Permalink to &quot;2. OpenAI&quot;">​</a></h3><p>直接连接 OpenAI 或任何 OpenAI 兼容的 API。</p><table tabindex="0"><thead><tr><th>配置项</th><th>说明</th><th>是否必需</th></tr></thead><tbody><tr><td><strong>OpenAI URL 地址</strong></td><td>API 端点（默认：<code>https://api.openai.com/v1</code>）</td><td>是</td></tr><tr><td><strong>OpenAI API Key</strong></td><td>您的 OpenAI API 密钥</td><td>是</td></tr><tr><td><strong>模型名称</strong></td><td>使用的模型（例如 <code>gpt-5</code>、<code>claude-sonnet-4-6</code>、<code>claude-opus-4-5</code>）</td><td>是</td></tr></tbody></table><p><strong>最适合：</strong> 直接使用 OpenAI 模型，或连接到提供 OpenAI 兼容 API 的第三方服务。</p><hr><h3 id="_3-amazon-bedrock" tabindex="-1">3. Amazon Bedrock <a class="header-anchor" href="#_3-amazon-bedrock" aria-label="Permalink to &quot;3. Amazon Bedrock&quot;">​</a></h3><p>使用 AWS Bedrock 获得企业级 AI 服务，具备 AWS 安全性和合规性。</p><table tabindex="0"><thead><tr><th>配置项</th><th>说明</th><th>是否必需</th></tr></thead><tbody><tr><td><strong>AWS Access Key</strong></td><td>IAM 访问密钥 ID</td><td>是</td></tr><tr><td><strong>AWS Secret Key</strong></td><td>IAM 秘密访问密钥</td><td>是</td></tr><tr><td><strong>AWS Session Token</strong></td><td>临时会话令牌（用于角色扮演）</td><td>否</td></tr><tr><td><strong>AWS 区域</strong></td><td>服务区域（例如 <code>us-east-1</code>）</td><td>是</td></tr><tr><td><strong>自定义 VPC 端点</strong></td><td>基于 VPC 访问的私有端点</td><td>否</td></tr><tr><td><strong>跨区域推理</strong></td><td>启用跨多个区域的推理</td><td>否</td></tr><tr><td><strong>模型名称</strong></td><td>Bedrock 模型标识符</td><td>是</td></tr></tbody></table><p><strong>最适合：</strong> 已投入 AWS 生态、需要企业级安全、合规控制和私有网络访问的组织。</p><hr><h3 id="_4-deepseek" tabindex="-1">4. DeepSeek <a class="header-anchor" href="#_4-deepseek" aria-label="Permalink to &quot;4. DeepSeek&quot;">​</a></h3><p>连接 DeepSeek API，获得强大的推理和编码能力。</p><table tabindex="0"><thead><tr><th>配置项</th><th>说明</th><th>是否必需</th></tr></thead><tbody><tr><td><strong>DeepSeek API Key</strong></td><td>您的 DeepSeek API 密钥</td><td>是</td></tr><tr><td><strong>模型名称</strong></td><td>使用的模型（例如 <code>deepseek-chat</code>、<code>deepseek-reasoner</code>）</td><td>是</td></tr></tbody></table><p><strong>最适合：</strong> 以高性价比获取具有强大推理和代码生成能力的模型。</p><hr><h3 id="_5-ollama-本地部署" tabindex="-1">5. Ollama（本地部署） <a class="header-anchor" href="#_5-ollama-本地部署" aria-label="Permalink to &quot;5. Ollama（本地部署）&quot;">​</a></h3><p>在本地运行模型，实现最大隐私保护和离线访问。</p><table tabindex="0"><thead><tr><th>配置项</th><th>说明</th><th>是否必需</th></tr></thead><tbody><tr><td><strong>Ollama URL 地址</strong></td><td>本地服务地址（默认：<code>http://localhost:11434</code>）</td><td>是</td></tr><tr><td><strong>模型名称</strong></td><td>本地已安装的模型（例如 <code>llama3</code>、<code>codellama</code>、<code>mistral</code>）</td><td>是</td></tr></tbody></table><p><strong>最适合：</strong> 气隙环境、对数据敏感的工作负载，或无需 API 费用的实验性使用。</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>测试连接前请确保 Ollama 服务正在运行。您可以使用 <code>ollama serve</code> 启动服务，使用 <code>ollama pull &lt;模型名称&gt;</code> 拉取模型。</p></div><hr><h2 id="配置技巧" tabindex="-1">配置技巧 <a class="header-anchor" href="#配置技巧" aria-label="Permalink to &quot;配置技巧&quot;">​</a></h2><ul><li><strong>每次修改后测试</strong> -- 修改任何提供商配置后，请务必点击&quot;测试连接&quot;。</li><li><strong>多模型支持</strong> -- 您可以同时配置多个提供商和模型，然后按对话切换使用。</li><li><strong>API 密钥安全</strong> -- Chaterm 将凭证存储在本地。请定期向您的提供商轮换密钥。</li><li><strong>性能考量</strong> -- 关注响应时间。本地模型（Ollama）没有网络延迟，但取决于您的硬件性能。云端模型在强大的服务器上更快，但会增加网络往返时间。</li></ul><hr><h2 id="相关文档" tabindex="-1">相关文档 <a class="header-anchor" href="#相关文档" aria-label="Permalink to &quot;相关文档&quot;">​</a></h2><ul><li><a href="/docs/ai/settings/">AI 设置</a> -- 逐步创建对话和配置提供商</li><li><a href="/docs/ai/preferences/">AI 偏好设置</a> -- 调整推理深度、自动执行和安全策略</li></ul>',42)]))}const b=e(n,[["render",l]]);export{m as __pageData,b as default};
